// Add to Interface:
/** Call dispose hook and remove the plugin from the active set */
readonly dispose: (pluginId: string) => Effect.Effect<void>

// Implementation in layer:
const disposePlugin = Effect.fn("Plugin.dispose")(function* (pluginId: string) {
  const s: any = yield* InstanceState.get(state)
  const idx = s.registrations.findIndex((r: PluginRegistration) => r.pluginId === pluginId)
  if (idx === -1) return
  const hook = s.hooks[idx]
  if (hook?.dispose) {
    yield* Effect.tryPromise({
      try: () => Promise.resolve(hook.dispose!()),
      catch: (err) => { log.error("plugin dispose hook failed", { pluginId, error: err }) },
    }).pipe(Effect.ignore)
  }
  s.hooks.splice(idx, 1)
  s.registrations.splice(idx, 1)
})

