// Clone output before each hook dispatch
// Shallow clone via spread for plain objects, structuredClone for complex
const clone = (val: any) => {
  if (typeof val !== 'object' || val === null) return val
  // Use structuredClone for arrays and plain objects to avoid shared references
  if (Array.isArray(val) || val.constructor === Object) {
    try { return structuredClone(val) } catch { return { ...val } }
  }
  return { ...val }
}

// In trigger():
const clonedOutput = clone(output)
yield* Effect.tryPromise({ try: () => fn(input, clonedOutput), ... })
